 1→import { type ReactNode, useCallback } from 'react';
 2→import { useListContext } from '../list_context';
 3→import './list_item.scss';
 4→
 5→export interface ListItemAccessory {
 6→  text?: string;
 7→  icon?: ReactNode;
 8→}
 9→
10→export interface ListItemProps {
11→  index: number;
12→  icon?: ReactNode;
13→  title: string;
14→  subtitle?: string;
15→  accessories?: ListItemAccessory[];
16→  onClick?: () => void;
17→}
18→
19→export function ListItem({
20→  index,
21→  icon,
22→  title,
23→  subtitle,
24→  accessories,
25→  onClick,
26→}: ListItemProps) {
27→  const { activeIndex, setActiveIndex } = useListContext();
28→  const isActive = activeIndex === index;
29→
30→  const handleMouseEnter = useCallback(() => {
31→    setActiveIndex(index);
32→  }, [
33→    index,
34→    setActiveIndex,
35→  ]);
36→
37→  return (
38→    <div
39→      className={`list-item${isActive ? ' list-item--active' : ''}`}
40→      data-list-index={index}
41→      role="option"
42→      aria-selected={isActive}
43→      onMouseEnter={handleMouseEnter}
44→      onClick={onClick}
45→    >
46→      <div className="list-item__left">
47→        {icon && <span className="list-item__icon">{icon}</span>}
48→        <span className="list-item__title">{title}</span>
49→        {subtitle && <span className="list-item__subtitle">{subtitle}</span>}
50→      </div>
51→      {accessories && accessories.length > 0 && (
52→        <div className="list-item__accessories">
53→          {accessories.map((accessory, i) => (
54→            <span key={i} className="list-item__accessory">
55→              {accessory.icon}
56→              {accessory.text && (
57→                <span className="list-item__accessory-text">
58→                  {accessory.text}
59→                </span>
60→              )}
61→            </span>
62→          ))}
63→        </div>
64→      )}
65→    </div>
66→  );
67→}
